input.command:
kubectl -n cockroachdb patch statefulset crdb-cluster --type=json -p='[
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/command/2",
    "value": "exec /cockroach/cockroach start --logtostderr=INFO --certs-dir=/cockroach/cockroach-certs --advertise-host=$(POD_NAME).crdb-cluster.$(POD_NAMESPACE).svc.cluster.local --http-addr=0.0.0.0:8080 --port=26257 --cache=25% --max-sql-memory=25% --join=crdb-cluster-0.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-1.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257,crdb-cluster-2.crdb-cluster.$(POD_NAMESPACE).svc.cluster.local:26257"
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/livenessProbe/httpGet/scheme",
    "value": "HTTPS"
  },
  {
    "op": "replace",
    "path": "/spec/template/spec/containers/0/readinessProbe/httpGet/scheme",
    "value": "HTTPS"
  },
  {
    "op": "add",
    "path": "/spec/template/spec/containers/0/volumeMounts/-",
    "value": {
      "name": "cockroachdb-certs",
      "mountPath": "/cockroach/cockroach-certs",
      "readOnly": true
    }
  },
  {
    "op": "add",
    "path": "/spec/template/spec/volumes",
    "value": [
      {
        "name": "cockroachdb-certs",
        "secret": {
          "secretName": "cockroachdb-certs",
          "defaultMode": 384
        }
      }
    ]
  }
]' 2>&1
